class MutableKey:
    def __init__(self, x):
        self.x = x
    def __hash__(self):
        return hash(self.x)
    def __eq__(self, o):
        return isinstance(o, MutableKey) and self.x == o.x

mk = MutableKey(1)
d = {mk: 'v'}
mk.x = 2
print('BUG', d.get(mk))

