from typing import Protocol

class Scorer(Protocol):
    def score(self, pair: tuple[str, str]) -> float: ...

class FakeScorer:
    def score(self, pair: tuple[str, str]) -> float:
        return 1.0 if pair[0] == pair[1] else 0.0

print(FakeScorer().score(('a', 'a')))

def apply(norm, text):
    return norm(text)

def strip_norm(s):
    return s.strip()
def casefold_norm(s):
    return s.casefold()

print(apply(strip_norm, '  X '))
print(apply(casefold_norm, 'AbC'))

